// Reference a Template Spec from a Bicep module
module storage 'ts:shared-rg/storage-template/1.0.0' = {
  name: 'storageDeployment'
  params: {
    storageName: 'myacctprod'
    environment: 'prod'
  }
}

from azure.core.exceptions import HttpResponseError

try:
    result = poller.result()
except HttpResponseError as e:
    print(f'Deployment failed: {e.error.code} — {e.error.message}')
    # Retrieve per-resource operation errors
    ops = client.deployment_operations.list(
        resource_group_name=rg_name,
        deployment_name=deployment_name,
    )
    for op in ops:
        if op.properties.provisioning_state == 'Failed':
            err = op.properties.status_message.error if op.properties.status_message else None
            target = op.properties.target_resource
            print(f'  Failed resource: {target.resource_name if target else "unknown"}')
            if err:
                print(f'  Error: {err.code} — {err.message}')
    raise

// Bicep — concise, type-safe, no quotes on property names
param storageName string
param location string = resourceGroup().location
param environment string = 'dev'

var storageSku = environment == 'prod' ? 'Standard_GRS' : 'Standard_LRS'

resource storage 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: storageName
  location: location
  sku: {
    name: storageSku
  }
  kind: 'StorageV2'
}

output storageId string = storage.id
output primaryEndpoint string = storage.properties.primaryEndpoints.blob
